var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네, 블랙 네트워크 쪽의 정보를 해킹한 기록이 그대로 남아 있어요.","JPN":"はい、ブラックネットワークの情報をハッキングした\\n記録がそのまま残っています。","ENG":"Yes, there's a record of them hacking into the Dark Network.","TWN":"是，發現了黑色網路上的資訊被入侵的記錄。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이렇게 뒤처리를 안 하고 흔적을 남기는 부류는 둘 중 하나죠. 멍청하거나, 겁이 없거나.","JPN":"こんな風に痕跡を残すやつは二択ですね。\\nただの間抜けか、怖いもの知らずか。","ENG":"People who don't bother to clean after themselves are either too stupid or too bold.","TWN":"留下如此明顯痕跡的人能分為兩種，要麼是蠢貨，要麼不怕死。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구출도 구출이지만, 맡긴 물건도 제대로 전해주도록 하세요.","JPN":"救出はもちろんですが、預けたものもきちんと\\n届けるように伝えてくださいね。","ENG":"While you're there to rescue Titan, also make sure that the item is safely delivered.","TWN":"除了救援之外，別忘了安全地轉交委託的東西。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님이 특별히 지시한 사항입니다.","JPN":"社長からの特命案件です。","ENG":"The Boss was very specific about that.","TWN":"這是老闆的特別指示。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......걱정 마세요. 두 임무 모두 확실히 해내겠습니다.","JPN":"……ご安心ください。両方とも確実にやり遂げます。","ENG":"Don't worry. We'll take care of both.","TWN":"……放心，兩個任務我都會完美完成的。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양은 언제나 믿음직하군요.","JPN":"シズカさんはいつも頼もしいわね。","ENG":"Seo Yoon, you're so reliable, as always.","TWN":"徐芸小姐總是這麼可靠。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이젠 정식 라이선스도 얻었으니 이전처럼 <color=#ffd34c>돌발상황에 따른 불가피한 현장대응</color> 같은 일은 없을 거라 기대하겠습니다.","JPN":"正式ライセンスも取得したことですし、今後は\\n<color=#ffd34c>突発的な事情による、やむを得ない現場対応</color>などは発生しないことを\\n期待しているわ。","ENG":"Now that you've acquired the official license, I expect there will be no more <color=#ffd34c>spontaneous actions to address emergency situations</color> like the last time.","TWN":"既然獲得了正式執照，希望不會出現像上次那樣的<color=#ffd34c>因突發情況而不可避免的現場對應</color>。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼요. 믿음과 신뢰가 바로 저의 모토잖아요?","JPN":"もちろんです、安心と信頼が私のモットーですから。","ENG":"Of course. Trust and credibility are my motto.","TWN":"當然，我的座右銘就是信任與信賴嘛。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잘 아시면서. 호호호.","JPN":"よくご存じのはずなのに、今さら水くさいですわ。オホホホ。","ENG":"You know that. Hah hah hah.","TWN":"您不是知道嘛，嘻嘻嘻。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그다지 잘 모르겠군요. 후후후......","JPN":"初耳な気がするのはなぜかしらね。ウフフフ……","ENG":"I don't think I do. Hah hah hah.","TWN":"我不是很懂喔，呵呵呵……"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 다녀오겠습니다, 부사장님.","JPN":"では、行ってきます、副社長。","ENG":"Well, if you'll excuse me, Vice President.","TWN":"那我走了，副總。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"오랜만의 작전이잖아! 두근거리는 걸, 대장!","JPN":"久々の作戦！　わくわくするな、隊長！","ENG":"We're on a mission after so long. I'm so excited, Cap!","TWN":"很久沒有參加作戰了！好興奮，隊長！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이번 작전의 주 목표가 요인 구출이라는 걸 알긴 아는 거야?","JPN":"作戦の主な目標は要人救出ってこと、わかってるの？","ENG":"Do you even know the main objective of this mission is VIP recovery?","TWN":"你沒有忘記本次作戰的主要目的是救援吧？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"괜히 날뛰다가 사고 쳐서 어렵게 받은 라이선스 박탈이나 당하지 말라고, 멍청아.","JPN":"むやみに暴れて何かやらかしたら、貴重なライセンスを\\n剥奪されるのよ。慎んでなさい、この脳筋イノシシ。","ENG":"You'd better not cause trouble. I don't want to lose our hard-earned license because of you.","TWN":"別惹事，若是闖禍會被剝奪執照的，笨蛋。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"내가 사고를 친다면 지금 당장일 것 같은데 어때? 앙!","JPN":"はぁ？　暴れるんだったら、今この瞬間が最高だと\\n思わねえか？　ああん！？","ENG":"How about I cause trouble right now? FOR YOU!","TWN":"信不信我現在就闖禍給你看？啊！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"얘, 얘들아 진정해......","JPN":"み、みんな、落ち着いてよ……","ENG":"G-guys, calm down...","TWN":"你、你們不要鬧了。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그보다 대장, 구출 대상이 그...... 정말이야?","JPN":"それより隊長。救出対象は、あの……本当なの？","ENG":"By the way, Cap. Is that VIP, erm, really...","TWN":"隊長，那個救援對象……是真的嗎？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하하, 그렇다는데? 사장님 딸이래.","JPN":"ハハ、そうらしいわよ？　社長の娘さんなんだって。","ENG":"Hah hah, yes. The Boss's daughter.","TWN":"哈哈，好像是的？是老闆的女兒。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"하, 하지만...... 사장님은 로봇인데......?","JPN":"で、でも……社長はロボットでしょ……？","ENG":"B-but... the Boss is a robot...","TWN":"但、但是……老闆不是機器人嗎……？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"아무렴 어때! 복잡하게 생각할 것 없잖아?","JPN":"いいじゃん、別に！　どうでもよくね？","ENG":"So what? You're thinking way too much.","TWN":"那又怎樣！不要想得太複雜？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"같은 공장에서 만들어졌다거나 뭐 그런 거겠지!","JPN":"親子で同じ工場でつくられたとかじゃねーの？","ENG":"I bet they were just made in the same factory, or something.","TWN":"或許是在同一個工廠生產的！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"유진이 말이 맞아. 우리가 사장님 사생활 까지 신경 쓸 필욘 없지.","JPN":"シロコの言うとおりよ。社長のプライベートまで\\n気にすることはない。","ENG":"Eujin is right. We shouldn't pry into the Boss's business, either.","TWN":"劉珍說得對，我們沒必要關心老闆的私生活。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"확실한 건 이번 구출 대상을 사장님께서 자식이라 부를만큼 아끼신다는 거야.","JPN":"確かなのは社長が「子ども」呼びをするほど、今回の\\n救出対象は大事に思われてるってこと。","ENG":"What matters is that our target is important to our Boss, enough to be called his daughter.","TWN":"重要的是老闆將這次的救援對象視如親生女兒。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어쩌면 후계자로서 언젠가 회사를 물려받을지도 모르잖아?","JPN":"もしかしたら後継者として、いつか会社を受け継ぐかも\\nしれないのよ？","ENG":"Who knows? She could be our next boss, too.","TWN":"沒准以後會成為老闆的接班人繼承公司喔？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어떤 회사에도 영원한 사장은 없는 법이니까. 후후후.","JPN":"どの会社にも不死身な社長なんていないからね。\\nフフフ。","ENG":"No president can be president forever. Hah hah.","TWN":"畢竟世上沒有永遠的老闆嘛，呵呵呵。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그, 그럼 이번 기회에 잘 보여서 점수를 얻는 게 좋겠네!","JPN":"そ、そうか。それなら今回うまくやって気に入られたほうが\\n良いよな！","ENG":"Then, we'd better impress her while we can!","TWN":"那、那這次一定要好好表現，給它留下好印象！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"좋아! 나한테 맡겨! 가자고 다들!","JPN":"よし！　俺にまかせろ！　行こうぜ、みんな！","ENG":"Alright! Leave it to me! Let's go!","TWN":"好！交給我！快出發吧！"},"stage":{"bg":"VEHICLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_20"},{"id":"L37_1","type":"dialog","speaker":"PIRATE_FOX_A_NULL","text":{"KOREA":"나포한 메카닉들을 개조할 준비가 끝났습니다.","JPN":"捕獲したメカニックを改造する準備ができました。","ENG":"We're ready to modify the captured mechs.","TWN":"改造抓捕的裝甲部隊已準備就緒。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"좋아. 유물을 차지하지 못한 건 아쉽지만 뜻밖의 대어를 낚았다.","JPN":"いいぞ。遺物獲得に失敗したのは残念だったが、\\n思いがけない収穫があった。","ENG":"Good. We didn't get the artifacts, but we've got something much better.","TWN":"好，雖然沒拿到遺物，卻有意外的收穫。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그 소문의 타이탄이 제 발로 내 손에 굴러 떨어질 줄이야......","JPN":"あの噂のタイタンが簡単に手に入るなんて、\\nまさに棚ぼた……","ENG":"Who knew the fabled Titan would fall right onto my lap?","TWN":"沒想到那個傳聞中的泰坦落到我的手裡……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이 녀석을 개조하면 퓨처 앳 워가 아니라 관리국과의 정면승부도 노려볼만하지.","JPN":"こいつを改造すればフューチャーアットウォーに限らず、\\n管理局との正面対決も狙える。","ENG":"With it on our side, we can take on Future-at-War, and even the Administration.","TWN":"成功改造這傢伙之後，不僅僅是天啟兵器，我們甚至能和管理局正面交鋒。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그렇게만 하면 관리국 놈들이 독점하고 있는 유물들도 모두 우리 것이 된다.","JPN":"そうなれば、管理局の奴らが独り占めしている遺物も\\n全部我々のもんだ。","ENG":"Then, we can take all the artifacts that the Administration has.","TWN":"這樣一來，管理局壟斷的遺物都會歸我們所有。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"큭큭큭, 기다려라 독재자 관리국 놈들!","JPN":"クククッ、今に見てろよ！　管理局の独裁者どもめ！","ENG":"Mwa hah hah! You just wait for me, greedy bureaucrats at the Administration!","TWN":"呵呵呵，等著吧，管理局的獨裁者們！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"네놈들에게 나눔의 기쁨이 어떤 것인지 알려주겠어.","JPN":"お前らに分け合う喜びがどんなものか、教えてやる。","ENG":"I'll teach you the joy of sharing.","TWN":"我要讓你們感受到分享的喜悅的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"대, 대장님?","JPN":"た、隊長！","ENG":"M-ma'am?","TWN":"隊、隊長？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L45_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"뭐냐? 내가 작품을 다루는 이런 중요한 타이밍에!","JPN":"何だ？　俺がコレクションを扱っている重要なタイミングに！","ENG":"What? I'm working on a masterpiece. I can't lose my concentration!","TWN":"什麼事？沒看到我在創造作品嗎！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"왠 차량 한대가 저희 기지로 접근 중이라고 합니다.","JPN":"正体不明の車両一台が、我々の基地に\\n接近しているそうです。","ENG":"A vehicle is approaching our base.","TWN":"有一個車輛正在靠近我們基地。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"차량? 그래서 어쩌라고? 그냥 함포로 날려버려.","JPN":"車両？　それが何だ？　艦砲でぶっ飛ばしちまえば\\nいいだろ？","ENG":"A vehicle? So what? Just blow it away with a cannon.","TWN":"車輛？那又怎樣？用艦炮炸飛。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"벌써 몇 번이나 발사했지만 전부 회피하거나 요격당하고 있습니다.","JPN":"もう何度も狙っていますが、すべて回避、または\\n迎撃されています。","ENG":"We tried. Several times. It's managed to evade—even intercept—our shots.","TWN":"已經發射好幾次了，但都被它躲過或截擊了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"구형 보병지원 차량을 개조한 것 같은데 분명 어디서 본 것 같아서 블랙네트워크에 자료를 검색해봤더니 이런 내용이......","JPN":"旧型の歩兵支援車を改造したもののようですが、\\nどこかで見た気がしたのでブラックネットワークで\\n検索してみたら、こんなものが……","ENG":"It's a modified old-model infantry support vehicle, and it looked strangely familiar. So I checked the Dark Network, and I found this.","TWN":"好像是由老款步兵支援車輛改造而成的，我們在黑色網路搜索了資料，結果找到了這樣的內容……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"언더컨트롤......?","JPN":"アンダーコントロール……？","ENG":"Undercontrol?","TWN":"地下支配者……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"알트 소대!","JPN":"アルト小隊！","ENG":"The ALT Squad!","TWN":"阿爾特小隊！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이것들, 블랙 네트워크에서 한동안 보이지 않는다 싶었더니 갑자기 여기에 나타나?","JPN":"ブラックネットワークで見かけなくなったと思ったら、\\nこんなところにいやがったのか！","ENG":"I wondered why they disappeared from the Dark Network. What are they doing here all of a sudden?","TWN":"這些傢伙，在黑色網路有段時間沒看到他們，竟然突然出現在這裡？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"실력이 꽤 쓸만하다는 평판이 많아서 내 밑에 들어왔다면 좋게 대우해줄 생각이었는데, 감히 우릴 적으로 돌리다니.","JPN":"なかなかの腕だと聞いていたから、俺の配下に\\nしてやるつもりだったのに、歯向かってくるなんてな。","ENG":"I heard many great things about the team; I even thought about taking them under my wing. How dare they show up to challenge me?","TWN":"本來很看好他們的實力，若加入我麾下本想善待他們的，沒想到竟敢與我們為敵。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"전투조 집합! 놈들에게 우리 찰거머리단의 힘을 똑똑히 보여주도록!","JPN":"戦隊は集結せよ！　我が粘着海賊団の力を\\n見せつけてやるのだ！","ENG":"Soldiers, gather around! Show them the power of the Leeches!","TWN":"戰鬥組集合！讓他們見識一下我們血蛭團的厲害！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};